/* config.h — generated by vcpkg portfile for Windows/MSVC builds */
#ifndef ZVBI_CONFIG_H
#define ZVBI_CONFIG_H

#define PACKAGE "zvbi"
#define PACKAGE_NAME "zvbi"
#define PACKAGE_VERSION "0.2.44"
#define VERSION "0.2.44"
#define PACKAGE_LOCALE_DIR ""

/* Byte order (Windows is always little-endian on x86/x64/ARM) */
#define Z_LITTLE_ENDIAN 1234
#define Z_BIG_ENDIAN    4321
#define Z_BYTE_ORDER    1234

/* iconv support */
#define HAVE_ICONV 1

/* Standard headers */
#define STDC_HEADERS 1
#define HAVE_STDBOOL_H 1
#define HAVE_STDINT_H 1
#define HAVE_INTTYPES_H 1
#define HAVE_STRING_H 1
#define HAVE_STDLIB_H 1
#define HAVE_MEMORY_H 1
#define HAVE_WINSOCK2_H 1

/* Functions available in the Windows CRT */
#define HAVE_MEMMOVE 1
#define HAVE_MEMSET 1
#define HAVE_STRCHR 1
#define HAVE_STRDUP 1
#define HAVE_STRERROR 1
#define HAVE_STRRCHR 1
#define HAVE_STRSTR 1
#define HAVE_STRTOL 1
#define HAVE_STRTOUL 1

/* Disabled platform-specific backends (Linux/BSD only) */
/* #undef ENABLE_V4L */
/* #undef ENABLE_V4L2 */
/* #undef ENABLE_DVB */
/* #undef ENABLE_BKTR */
/* #undef ENABLE_PROXY */

/* No strerror_r on Windows */
/* #undef HAVE_GNU_STRERROR_R */
/* #undef HAVE_SUSV3_STRERROR_R */

/* No dlopen/dlsym on Windows (disables dynamic export-plugin loading;
   built-in text/HTML/VTX exporters still work) */
/* #undef HAVE_DLFCN_H */

/* No NLS on Windows vcpkg build */
/* #undef ENABLE_NLS */
#define _(x) (x)
#define N_(x) (x)
/* ngettext, textdomain, bindtextdomain, bind_textdomain_codeset are
   defined in intl-priv.h (in the #else / !ENABLE_NLS branch).
   Defining them here as well triggers C4005 macro-redefinition warnings. */

/* MSVC: ssize_t is not a standard C type */
#ifdef _MSC_VER
#  include <BaseTsd.h>
   typedef SSIZE_T ssize_t;
#endif

/* MSVC: mode_t for file permissions */
#ifdef _MSC_VER
   typedef unsigned short mode_t;
#endif

/* POSIX file permission constants (not available on MSVC) */
#ifdef _MSC_VER
#  include <sys/stat.h>
#  ifndef S_IRUSR
#    define S_IRUSR _S_IREAD
#    define S_IWUSR _S_IWRITE
#    define S_IRGRP 0
#    define S_IWGRP 0
#    define S_IROTH 0
#    define S_IWOTH 0
#  endif
#  ifndef S_ISREG
#    define S_ISREG(m) (((m) & _S_IFMT) == _S_IFREG)
#  endif
#endif

/* SSIZE_MAX (POSIX, not in MSVC) */
#ifndef SSIZE_MAX
#  ifdef _WIN64
#    define SSIZE_MAX ((ssize_t)0x7FFFFFFFFFFFFFFFLL)
#  else
#    define SSIZE_MAX ((ssize_t)0x7FFFFFFF)
#  endif
#endif

/* __PRETTY_FUNCTION__ is a GCC extension */
#ifndef __PRETTY_FUNCTION__
#  define __PRETTY_FUNCTION__ __FUNCTION__
#endif

/* MSVC: strip all GCC __attribute__((...)) annotations */
#ifdef _MSC_VER
#  define __attribute__(x)
#endif

/* MSVC: __inline__ is a GCC keyword; MSVC uses __inline */
#ifdef _MSC_VER
#  define __inline__ __inline
#endif

/* MSVC: POSIX localtime_r / gmtime_r compatibility wrappers.
   MSVC provides localtime_s / gmtime_s with reversed argument order
   and errno_t return type instead of struct tm*.
   We use zvbi_-prefixed helpers + macros to avoid collisions with
   other libraries that may provide their own localtime_r/gmtime_r.
   Used by pdc.c (3 calls) and packet.c (1 call). */
#ifdef _MSC_VER
#  include <time.h>
static __inline struct tm *zvbi_localtime_r(const time_t *timep, struct tm *result)
{
    return localtime_s(result, timep) == 0 ? result : NULL;
}
static __inline struct tm *zvbi_gmtime_r(const time_t *timep, struct tm *result)
{
    return gmtime_s(result, timep) == 0 ? result : NULL;
}
#  define localtime_r zvbi_localtime_r
#  define gmtime_r    zvbi_gmtime_r
#endif

#endif /* ZVBI_CONFIG_H */
